def fibonacci(n):
    if n <= 0:
        return 0
    elif n == 1:
        return 1
    else:
        a, b = 0, 1
        for _ in range(2, n + 1):
            a, b = b, a + b
        return b

# 测试
assert fibonacci(0) == 0
assert fibonacci(1) == 1
assert fibonacci(5) == 5
assert fibonacci(10) == 55
print('Fibonacci tests passed!')

def find_key(data, target_key):
    if isinstance(data, dict):
        if target_key in data:
            return data[target_key]
        for key, value in data.items():
            result = find_key(value, target_key)
            if result is not None:
                return result
    elif isinstance(data, list):
        for item in data:
            result = find_key(item, target_key)
            if result is not None:
                return result
    return None

# 测试
data = {'a': 1, 'b': {'c': 2, 'd': {'e': 3}}}
assert find_key(data, 'e') == 3
assert find_key(data, 'a') == 1
assert find_key(data, 'z') is None
print('Nested dict tests passed!')

import json

def validate_json(json_str, schema):
    try:
        data = json.loads(json_str)

        for key, expected_type in schema.items():
            if key not in data:
                return False, f'Missing key: {key}'

            if expected_type == 'string' and not isinstance(data[key], str):
                return False, f'Key {key} should be string'
            elif expected_type == 'number' and not isinstance(data[key], (int, float)):
                return False, f'Key {key} should be number'
            elif expected_type == 'boolean' and not isinstance(data[key], bool):
                return False, f'Key {key} should be boolean'
            elif expected_type == 'array' and not isinstance(data[key], list):
                return False, f'Key {key} should be array'
            elif expected_type == 'object' and not isinstance(data[key], dict):
                return False, f'Key {key} should be object'

        return True, 'Valid'
    except json.JSONDecodeError as e:
        return False, f'Invalid JSON: {str(e)}'

# 测试
schema = {'name': 'string', 'age': 'number', 'active': 'boolean'}
valid_json = '{"name": "John", "age": 30, "active": true}'
invalid_json = '{"name": "John", "age": "thirty"}'

assert validate_json(valid_json, schema)[0] == True
assert validate_json(invalid_json, schema)[0] == False
print('JSON validation tests passed!')
